import crypto from "node:crypto";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
const FALLBACK_KEY_PATH = path.join(os.homedir(), ".config", "bitfab", "agent-session-key");
function readOrCreateFallbackKey() {
    try {
        const existing = fs.readFileSync(FALLBACK_KEY_PATH, "utf-8").trim();
        if (existing) {
            return existing;
        }
    }
    catch {
        // file doesn't exist
    }
    const key = crypto.randomUUID();
    fs.mkdirSync(path.dirname(FALLBACK_KEY_PATH), { recursive: true });
    fs.writeFileSync(FALLBACK_KEY_PATH, `${key}\n`);
    return key;
}
export function resolveAgentSessionKey() {
    return (process.env.CLAUDE_CODE_SESSION_ID ??
        process.env.CURSOR_SESSION_ID ??
        process.env.CODEX_THREAD_ID ??
        readOrCreateFallbackKey());
}
